import Spinner from './Spinner';
import TodoInput from './TodoInput';
import classes from './TodoItems.module.css'
import TodoList from './TodoList';
import { useState } from 'react'
import * as taskService from '../services/taskService'


const taskAction={
    Edit:'edit',
    Delete:'delete'
}
const TodoItems = (props,loader) => {

      const [taskAction, setTaskAction]=useState({
        task:null,
        action:null,
      })

const detailsClickHandler = (id) =>{
        taskService.getOne(id)
        .then(task=>{
            setTaskAction({
                task,
                action:taskAction.Edit
            })
        })
    }

    const deleteClickHandler = (id) =>{
        taskService.getOne(id)
        .then(task=>{
            setTaskAction({
                task,
                action:taskAction.Delete
            })
        })
    }



return (
<section className={classes['todo-items-section']}>
{taskAction && 'Ova e test'}
{props.loading && <Spinner/>}
 <ul className={classes['list-wrapper']}>
{props.task.map(x=>  <TodoList detailsHandler={taskAction}  {...x}/>)}
</ul>
</section>
);
}

export default TodoItems
